import { useState } from 'react';
import { useNavigate } from 'react-router-dom'; // Bá»• sung cÃ´ng cá»¥ chuyá»ƒn trang

function Login() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');

  const navigate = useNavigate(); // Khá»Ÿi táº¡o cÃ´ng cá»¥

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('https://doan-qlk.onrender.com/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });

      const data = await response.json();

      if (data.success) {
        // 1. LÆ°u "tháº» ra vÃ o" (token) vÃ  thÃ´ng tin user vÃ o bá»™ nhá»› trÃ¬nh duyá»‡t
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));

        // 2. Chuyá»ƒn hÆ°á»›ng tháº³ng vÃ o trang Tá»•ng quan
        navigate('/');
      } else {
        setMessage(`âŒ ${data.message}`);
      }
    } catch (error) {
      setMessage('âŒ Lá»—i khÃ´ng káº¿t ná»‘i Ä‘Æ°á»£c Backend!');
    }
  };

  return (



